-- Update all 9 projects with artistic descriptions from LLM-generated content
-- Uses full_xx values (not short) for rich, narrative descriptions

-- 1. Portfolio
UPDATE feature_projects SET
  description_en = 'Imagine a vigilant scout, scanning the digital horizon for the newest innovations, then a skilled artisan, reshaping those discoveries into compelling stories across three languages. This platform is that very artisan, a tireless weaver of tales that not only populate my personal showcase but also illuminate the broader tech landscape. It''s a living, breathing chronicle, ensuring vital insights reach diverse audiences through social channels and even captivating video narratives, all orchestrated with an elegant, invisible hand. It''s a testament to how meticulous craftsmanship can bring clarity and connection to a fast-moving world.',
  description_no = 'Se for deg en våken speider som skanner den digitale horisonten for de nyeste innovasjonene, deretter en dyktig håndverker som omformer disse funnene til fengslende historier på tre språk. Denne plattformen er nettopp denne håndverkeren, en utrettelig vever av fortellinger som ikke bare fyller mitt personlige utstillingsvindu, men også lyser opp det bredere teknologilandskapet. Det er en levende, pustende krønike som sikrer at viktig innsikt når ulike publikum gjennom sosiale kanaler og til og med fengslende videofortellinger, alt orkestrert med en elegant, usynlig hånd. Et bevis på hvordan grundig håndverk kan bringe klarhet og forbindelse til en verden i stadig bevegelse.',
  description_ua = 'Уявіть собі пильного розвідника, що сканує цифровий горизонт у пошуках новітніх інновацій, а потім вправного майстра, який перетворює ці відкриття на захопливі історії трьома мовами. Ця платформа і є тим майстром, невтомним ткачем оповідей, що не лише наповнюють мою особисту вітрину, а й висвітлюють ширший технологічний ландшафт. Це жива, дихаюча хроніка, яка гарантує, що важливі ідеї досягають різноманітної аудиторії через соціальні мережі та навіть захопливі відео-розповіді, все це оркестровано елегантною, невидимою рукою. Це свідчення того, як ретельна майстерність може принести ясність і зв''язок у швидкоплинний світ.'
WHERE id = 'portfolio';

-- 2. JobBot
UPDATE feature_projects SET
  description_en = 'Imagine a world where the relentless quest for a new role transforms into a serene journey. This digital companion acts as your personal scout, tirelessly sifting through the vast Norwegian job landscape. It understands the nuances of each opportunity, then, with the finesse of a seasoned storyteller, crafts bespoke cover letters tailored to resonate. A diligent digital hand then navigates complex application forms across countless sites, remembering your details like an old friend. You receive whispered notifications of new prospects and a strategic map of your journey, freeing you to focus on your aspirations, not the paperwork.',
  description_no = 'Forestille deg en verden hvor den nådeløse jakten på en ny rolle forvandles til en rolig reise. Denne digitale følgesvennen fungerer som din personlige speider, som utrettelig saumfarer det store norske jobblandskapet. Den forstår nyansene i hver mulighet, og med en erfaren fortellers finesse, skaper den skreddersydde søknadsbrev som treffer. En flittig digital hånd navigerer så komplekse søknadsskjemaer på utallige nettsteder, og husker dine detaljer som en gammel venn. Du mottar hviskende varsler om nye prospekter og et strategisk kart over reisen din, noe som frigjør deg til å fokusere på dine ambisjoner, ikke papirarbeidet.',
  description_ua = 'Уявіть світ, де невпинний пошук нової роботи перетворюється на спокійну подорож. Цей цифровий компаньйон діє як ваш особистий розвідник, невтомно просіваючи величезний норвезький ринок праці. Він розуміє нюанси кожної можливості, а потім, з витонченістю досвідченого оповідача, створює індивідуальні супровідні листи, що справді чіпляють. Старанна цифрова рука потім заповнює складні форми на незліченних сайтах, запам''ятовуючи ваші дані, немов старий друг. Ви отримуєте тихі сповіщення про нові перспективи та стратегічну карту вашої подорожі, звільняючи вас зосередитися на ваших прагненнях, а не на паперовій тяганині.'
WHERE id = 'jobbot';

-- 3. Elvarika (DB id is project_23mai)
UPDATE feature_projects SET
  description_en = 'Elvarika is a beacon for those embarking on a new chapter in Norway, a melodic bridge built for the heart''s journey into a new tongue. It whispers the secrets of Norwegian into your ear, transforming the daunting pages of textbooks into a personalized symphony of learning. Through the magic of spoken word and intelligent recall, Elvarika ensures that every new phrase not only finds its way to your memory but also dances gracefully off your tongue, empowering you to weave your unique narrative into the vibrant tapestry of Norwegian life.',
  description_no = 'Elvarika er et fyrtårn for de som legger ut på et nytt kapittel i Norge, en melodisk bro bygget for hjertets reise inn i et nytt språk. Den hvisker hemmelighetene til norsk i øret ditt, og forvandler de skremmende sidene i lærebøker til en personlig symfoni av læring. Gjennom magien av det talte ord og intelligent gjenkalling, sikrer Elvarika at hver ny frase ikke bare finner veien til minnet ditt, men også danser grasiøst fra tungen din, og gir deg muligheten til å veve din unike fortelling inn i det levende teppet av norsk liv.',
  description_ua = 'Ельваріка — це маяк для тих, хто розпочинає нову главу в Норвегії, мелодійний міст, створений для подорожі серця в нову мову. Вона шепоче секрети норвезької мови у ваше вухо, перетворюючи складні сторінки підручників на персоналізовану симфонію навчання. Завдяки магії розмовного слова та інтелектуального запам''ятовування, Ельваріка гарантує, що кожна нова фраза не тільки знайде шлях до вашої пам''яті, але й граціозно зійде з вашого язика, надаючи вам можливість вплести свою унікальну розповідь у яскраве полотно норвезького життя.'
WHERE id = 'project_23mai';

-- 4. Calendar Bot
UPDATE feature_projects SET
  description_en = 'Imagine a calm harbor amidst a sea of conflicting appointments – this bot is that beacon. It seamlessly gathers all your children''s sports commitments from multiple sources, weaving them into a single, clear Google Calendar tapestry. A clever digital assistant then steps in, not just listing events, but thoughtfully suggesting the best times, like a wise mentor guiding your family''s flow. Parents gain a secure control panel, while everyone else enjoys a transparent window into the week''s adventures, ensuring no sprint or practice is ever missed. It''s the quiet architect of family harmony, ensuring every child finds their field of play, stress-free.',
  description_no = 'Se for deg en rolig havn midt i et hav av motstridende avtaler – denne boten er det fyrtårnet. Den samler sømløst alle barnas sportsforpliktelser fra flere kilder, og vever dem inn i et enkelt, oversiktlig Google Kalender-teppe. En smart digital assistent trer så inn, ikke bare lister opp hendelser, men foreslår omtenksomt de beste tidspunktene, som en klok veileder for familiens flyt. Foreldre får et sikkert kontrollpanel, mens alle andre nyter et gjennomsiktig vindu inn i ukens eventyr, noe som sikrer at ingen sprint eller trening blir glemt. Det er den stille arkitekten bak familieharmonien, som sikrer at hvert barn finner sin lekeplass, stressfritt.',
  description_ua = 'Уявіть собі тиху гавань серед моря суперечливих зустрічей – цей бот є тим маяком. Він бездоганно збирає всі спортивні зобов''язання ваших дітей з численних джерел, вплітаючи їх в єдиний, зрозумілий гобелен Google Календаря. Потім вступає розумний цифровий помічник, не просто перераховуючи події, а вдумливо пропонуючи найкращий час, наче мудрий наставник, що керує потоком родини. Батьки отримують безпечну панель керування, тоді як усі інші насолоджуються прозорим вікном у пригоди тижня, гарантуючи, що жодне тренування не буде пропущено. Це тихий архітектор сімейної гармонії, що забезпечує кожній дитині її поле для гри, без стресу.'
WHERE id = 'calendar_bot';

-- 5. Ghost Interviewer
UPDATE feature_projects SET
  description_en = 'Imagine a quiet, patient guide who sits with you, asking the tough questions, listening intently to every word. This project crafts that very space – a private rehearsal room where your aspirations meet practical refinement. It gently probes, then illuminates your strengths and areas for growth, offering immediate, insightful feedback on your answers. For those navigating new shores, particularly the vibrant Norwegian landscape, it''s a bridge of confidence, ensuring your true potential shines through in any language.',
  description_no = 'Tenk deg en tålmodig veileder som sitter med deg, stiller de utfordrende spørsmålene og lytter nøye til hvert svar. Dette prosjektet skaper nettopp et slikt rom – et privat øvingslokale hvor ambisjonene dine møter praktisk finpussing. Det undersøker forsiktig, og belyser deretter dine styrker og utviklingsområder, med umiddelbar, innsiktsfull tilbakemelding. For de som navigerer i nye farvann, spesielt det pulserende norske arbeidsmarkedet, er det en bro av selvtillit som sikrer at ditt sanne potensial skinner gjennom, uansett språk.',
  description_ua = 'Уявіть собі тихого, терплячого провідника, який сидить поруч з вами, ставить складні запитання та уважно слухає кожне слово. Цей проєкт створює саме такий простір – приватну репетиційну кімнату, де ваші прагнення зустрічаються з практичним шліфуванням. Він делікатно досліджує, а потім висвітлює ваші сильні сторони та зони росту, пропонуючи миттєвий, глибокий зворотний зв''язок щодо ваших відповідей. Для тих, хто долає нові горизонти, особливо на жвавому норвезькому ринку праці, це міст впевненості, що гарантує, що ваш справжній потенціал засяє, незалежно від мови.'
WHERE id = 'ghost_interviewer';

-- 6. Eye+ Camera Cloud
UPDATE feature_projects SET
  description_en = 'Imagine a quiet guardian, its gaze sweeping across every corner of your cherished spaces. This platform weaves together the watchful eyes of many cameras into a single, seamless tapestry, delivering live moments directly to you. Should a shadow stir where it shouldn''t, an immediate whisper reaches your ear. And for those moments you need to revisit, it acts as a meticulous memory keeper, allowing you to unfurl the past and understand every unfolding event with clarity. It''s a peace of mind, tailored with precision, ensuring only the right eyes see what they need to see.',
  description_no = 'Forestil deg en stille vokter, hvis blikk feier over hver krik og krok av dine kjære områder. Denne plattformen vever sammen mange kameraers våkne øyne til ett sømløst teppe, og leverer levende øyeblikk direkte til deg. Skulle en uønsket skygge røre seg, når en umiddelbar hvisken øret ditt. Og for de øyeblikkene du trenger å se igjen, fungerer den som en grundig minnebevarer, slik at du kan rulle ut fortiden og forstå hver hendelse med klarhet. Det er en ro i sjelen, nøyaktig skreddersydd, som sikrer at kun de rette øynene ser det de trenger å se.',
  description_ua = 'Уявіть собі тихого охоронця, чий погляд охоплює кожен куточок ваших дорогих просторів. Ця платформа об''єднує пильні очі багатьох камер в єдине, безшовне полотно, доставляючи живі моменти прямо до вас. Якщо ж тінь з''явиться там, де її не повинно бути, до вашого вуха миттєво долинає шепіт. А для тих моментів, які потрібно переглянути, вона слугує ретельним зберігачем пам''яті, дозволяючи розгорнути минуле та з ясністю зрозуміти кожну подію. Це спокій душі, точно налаштований, що гарантує, що лише правильні очі бачать те, що їм потрібно.'
WHERE id = 'eyeplus';

-- 7. Lingva AI (lingleverika)
UPDATE feature_projects SET
  description_en = 'Imagine a world where the whispers of one culture echo clearly in the ears of another. This platform is a bridge of understanding, built from the very fabric of spoken words. It listens to the soul of video content, transcending the babel of tongues to reveal its core message. Whether it''s the rich tapestry of Norwegian, the universal hum of English, the ancient cadence of Arabic, or the vibrant rhythm of Somali, it captures every nuance. Beyond mere translation, it distills lengthy narratives into luminous summaries, plucking out the golden threads of key moments and weaving them into a searchable chronicle.',
  description_no = 'Forestil deg en verden hvor hvisken fra én kultur gjenlyder klart i ørene til en annen. Denne plattformen er en bro av forståelse, bygget av selve stoffet i talte ord. Den lytter til sjelen i videoinnhold, og overskrider babels forvirring for å avsløre dens kjernemelding. Enten det er det rike teppet av norsk, den universelle summingen av engelsk, den eldgamle kadensen av arabisk, eller den levende rytmen av somali, fanger den hver nyanse. Utover enkel oversettelse, destillerer den lange fortellinger til lysende sammendrag, plukker ut de gylne trådene av nøkkeløyeblikk og vever dem inn i en søkbar krønike.',
  description_ua = 'Уявіть світ, де шепіт однієї культури чітко лунає у вухах іншої. Ця платформа — міст розуміння, побудований із самої тканини сказаних слів. Вона слухає душу відеоконтенту, долаючи вавилонську плутанину мов, щоб розкрити його основне повідомлення. Чи то багатий гобелен норвезької, універсальне гудіння англійської, стародавній ритм арабської, чи жвавий ритм сомалійської, вона вловлює кожен нюанс. Окрім простого перекладу, вона перетворює довгі розповіді на яскраві підсумки, витягуючи золоті нитки ключових моментів і вплітаючи їх у пошукову хроніку.'
WHERE id = 'lingleverika';

-- 8. YouTube Channel Manager
UPDATE feature_projects SET
  description_en = 'This tireless digital artisan acts as your channel''s invisible architect, transforming raw ideas and articles into captivating visual stories. It''s a meticulous curator, crafting irresistible thumbnails, optimizing every word for discovery, and ensuring each video finds its perfect moment to shine. From the quiet birth of an idea to its grand premiere across countless screens, this system orchestrates every detail, freeing creators to focus on their vision while their narratives effortlessly reach a global audience.',
  description_no = 'Denne utrettelige digitale håndverkeren fungerer som kanalens usynlige arkitekt, som forvandler rå ideer og artikler til fengslende visuelle historier. Den er en omhyggelig kurator, som lager uimotståelige miniatyrbilder, optimerer hvert ord for oppdagelse, og sikrer at hver video finner sitt perfekte øyeblikk til å skinne. Fra en idés stille fødsel til dens store premiere på utallige skjermer, orkestrerer dette systemet hver detalj, slik at skapere kan fokusere på sin visjon mens deres fortellinger uanstrengt når et globalt publikum.',
  description_ua = 'Цей невтомний цифровий майстер служить невидимим архітектором вашого каналу, перетворюючи сирі ідеї та статті на захопливі візуальні історії. Це ретельний куратор, який створює неперевершені мініатюри, оптимізує кожне слово для пошуку та гарантує, що кожне відео знайде свій ідеальний момент для блиску. Від тихого народження ідеї до її грандіозної прем''єри на незліченних екранах, ця система організує кожну деталь, звільняючи творців зосередитися на своєму баченні, тоді як їхні наративи без зусиль досягають глобальної аудиторії.'
WHERE id = 'youtube_manager';

-- 9. BoyTasks (new project — INSERT with ON CONFLICT for safety)
INSERT INTO feature_projects (id, name_en, name_no, name_ua, description_en, description_no, description_ua, image_url)
VALUES (
  'boytasks',
  'BoyTasks',
  'BoyTasks',
  'BoyTasks',
  'Imagine a digital guardian, a wise old storyteller, that weaves daily lessons into an exciting adventure. For three young scholars, this system transforms the allure of screens into a thrilling quest. Each morning, a scroll arrives bearing challenges in numbers, words, and grammar. As they conquer each task, a piece of a hidden cipher is revealed. Only when all brothers unite their efforts, piecing together the complete code, does the digital gate to their favorite videos swing open, rewarding their shared diligence and sparking a love for collaborative learning. It''s a gentle nudge towards knowledge, disguised as a daily game.',
  'Se for deg en digital veiviser som forvandler daglige lekser til en spennende skattejakt. For tre unge utforskere er skjermens lokkelse nå knyttet til et felles oppdrag. Hver morgen ankommer en liste med utfordringer i matematikk, lesing og grammatikk. Etter hvert som de mestrer oppgavene, avdekkes en del av en skjult kode. Først når alle brødrene samarbeider og setter sammen den komplette koden, åpnes porten til deres digitale underholdning, som en belønning for deres felles innsats og en gnist til livslang læring. Det er et vennlig dytt mot kunnskap, forkledd som et daglig spill.',
  'Уявіть собі цифрового охоронця, мудрого оповідача, який щоденні уроки перетворює на захопливу пригоду. Для трьох юних дослідників ця система перетворює привабливість екранів на захопливий квест. Щоранку приходить сувій із завданнями з математики, читання та граматики. Коли вони долають кожне завдання, розкривається частина прихованого шифру. Лише коли всі брати об''єднують свої зусилля, складаючи повний код, цифрові ворота до їхніх улюблених відео відчиняються, винагороджуючи їхню спільну старанність та запалюючи любов до колективного навчання. Це ніжний поштовх до знань, замаскований під щоденну гру.',
  '/images/projects/boytasks-cover.jpg'
)
ON CONFLICT (id) DO UPDATE SET
  description_en = EXCLUDED.description_en,
  description_no = EXCLUDED.description_no,
  description_ua = EXCLUDED.description_ua,
  image_url = EXCLUDED.image_url;
